using UnityEngine;

/// <summary>
/// Objectivo cumprido quando o inimigo com "Enemy Instance Id" =
/// <see cref="enemyInstanceId"/> entra num estado terminal (Morto/Desactivado —
/// EnemyController.OnAnyEnemyDefeated, Tarefa #22). Pensado para "derrota o
/// guardião X antes de avançar" — reaproveita o mesmo "Enemy Instance Id" já
/// usado por EnemyCondition/puzzles (ver EnemyController).
///
/// Se o inimigo já estiver num estado terminal (ex: já derrotado numa sessão
/// anterior — EnemyRespawn/PlayerProgress, Tarefa 7.3) ao iniciar o desafio, o
/// objectivo já começa cumprido.
///
/// Objectivo binário (sem contador) — <see cref="TargetProgress"/> devolve -1.
/// </summary>
[System.Serializable]
public class Objective_DefeatSpecificEnemy : ChallengeObjective
{
    [Tooltip("\"Enemy Instance Id\" (campo no EnemyController do inimigo) a derrotar.")]
    public string enemyInstanceId;

    [System.NonSerialized] private bool defeated;

    public override void ResetState()
    {
        EnemyController.OnAnyEnemyDefeated -= HandleEnemyDefeated;
        EnemyController.OnAnyEnemyDefeated += HandleEnemyDefeated;

        var existing = EnemyController.FindById(enemyInstanceId);
        defeated = existing != null && existing.IsTerminal;
    }

    private void HandleEnemyDefeated(EnemyController enemy)
    {
        if (enemy.EnemyInstanceId == enemyInstanceId)
            defeated = true;
    }

    public override bool IsComplete() => defeated;
}

/// <summary>
/// Objectivo cumprido ao derrotar pelo menos <see cref="amount"/> inimigos
/// DURANTE o desafio (EnemyController.OnAnyEnemyDefeated, Tarefa #22).
/// Contador global — não precisa de listar inimigos no Inspector, conta
/// qualquer inimigo que entre num estado terminal (Morto/Desactivado) enquanto
/// o desafio estiver activo, incluindo inimigos criados/spawnados depois do
/// início.
///
/// Mostra "derrotados/amount" no HUD (Tarefa #12).
/// </summary>
[System.Serializable]
public class Objective_DefeatEnemyCount : ChallengeObjective
{
    [Tooltip("Se definido, só conta derrotas de inimigos com este EnemyData. Se vazio, conta qualquer inimigo.")]
    public EnemyData enemyFilter;

    [Tooltip("Número de inimigos a derrotar durante o desafio.")]
    [Min(1)] public int amount = 1;

    [System.NonSerialized] private int count;

    public override void ResetState()
    {
        EnemyController.OnAnyEnemyDefeated -= HandleEnemyDefeated;
        EnemyController.OnAnyEnemyDefeated += HandleEnemyDefeated;
        count = 0;
    }

    private void HandleEnemyDefeated(EnemyController enemy)
    {
        if (enemyFilter != null && enemy.Data != enemyFilter) return;
        count++;
    }

    public override bool IsComplete() => count >= amount;

    public override int CurrentProgress() => Mathf.Min(count, amount);

    public override int TargetProgress() => amount;
}
